body.script:
/* ---- PARTICLES ---- */
(function(){
  const container = document.getElementById('particles');
  const colors = ['#00d4ff','#7c3aed','#06ffa5','#fbbf24'];
  for(let i=0;i<25;i++){
    const p = document.createElement('div');
    const size = Math.random()*6+2;
    const color = colors[Math.floor(Math.random()*colors.length)];
    const left = Math.random()*100;
    const delay = Math.random()*15;
    const duration = Math.random()*15+10;
    p.className='particle';
    p.style.cssText=`width:${size}px;height:${size}px;left:${left}%;background:${color};animation-delay:${delay}s;animation-duration:${duration}s;`;
    container.appendChild(p);
  }
})();

/* ---- DARK / LIGHT THEME TOGGLE ---- */
const themeToggle = document.getElementById('themeToggle');
const themeIcon   = document.getElementById('themeIcon');
const html        = document.documentElement;
themeToggle.addEventListener('click',()=>{
  const isDark = html.getAttribute('data-theme')==='dark';
  html.setAttribute('data-theme', isDark?'light':'dark');
  themeIcon.className = isDark ? 'fas fa-sun' : 'fas fa-moon';
});

/* ---- HAMBURGER / MOBILE MENU ---- */
const hamburger  = document.getElementById('hamburger');
const mobileMenu = document.getElementById('mobileMenu');
hamburger.addEventListener('click',()=>{
  mobileMenu.classList.toggle('open');
});
document.querySelectorAll('.mobile-link').forEach(l=>{
  l.addEventListener('click',()=>mobileMenu.classList.remove('open'));
});

/* ---- SCROLL REVEAL ---- */
const revealObserver = new IntersectionObserver((entries)=>{
  entries.forEach(e=>{
    if(e.isIntersecting) e.target.classList.add('visible');
  });
},{threshold:0.12});
document.querySelectorAll('.reveal,.reveal-left,.reveal-right').forEach(el=>revealObserver.observe(el));

/* ---- ANIMATED COUNTERS ---- */
function animateCounter(el){
  const target = +el.dataset.target;
  let current = 0;
  const step = Math.ceil(target/60);
  const timer = setInterval(()=>{
    current = Math.min(current+step, target);
    el.textContent = current + '+';
    if(current>=target) clearInterval(timer);
  },30);
}
const counterObserver = new IntersectionObserver((entries)=>{
  entries.forEach(e=>{
    if(e.isIntersecting){
      document.querySelectorAll('.counter-num').forEach(animateCounter);
      counterObserver.disconnect();
    }
  });
},{threshold:0.5});
const countersSection = document.querySelector('.counters');
if(countersSection) counterObserver.observe(countersSection);

/* ---- SKILL BAR ANIMATION ---- */
const skillObserver = new IntersectionObserver((entries)=>{
  entries.forEach(e=>{
    if(e.isIntersecting){
      document.querySelectorAll('.skill-fill').forEach(fill=>{
        fill.style.width = fill.dataset.width + '%';
      });
      skillObserver.disconnect();
    }
  });
},{threshold:0.2});
const skillsSection = document.querySelector('.skills');
if(skillsSection) skillObserver.observe(skillsSection);

/* ---- CERTIFICATE SLIDER ---- */
(function(){
  const track  = document.getElementById('certTrack');
  const dotsEl = document.getElementById('certDots');
  if(!track) return;

  const cards     = track.querySelectorAll('.cert-card');
  const total     = cards.length;
  let current     = 0;
  let cardWidth   = 0;
  let visible     = 3;

  function calcVisible(){
    const w = window.innerWidth;
    visible = w<600 ? 1 : w<900 ? 2 : 3;
    cardWidth = cards[0] ? cards[0].offsetWidth + 24 : 324;
  }

  // Build dots
  function buildDots(){
    dotsEl.innerHTML='';
    const pages = Math.ceil(total/visible);
    for(let i=0;igoTo(i));
      dotsEl.appendChild(dot);
    }
  }

  function goTo(page){
    calcVisible();
    const pages = Math.ceil(total/visible);
    current = Math.max(0,Math.min(page,pages-1));
    track.style.transform=`translateX(-${current*visible*cardWidth}px)`;
    dotsEl.querySelectorAll('.cert-dot').forEach((d,i)=>d.classList.toggle('active',i===current));
  }

  document.getElementById('certNext').addEventListener('click',()=>goTo(current+1));
  document.getElementById('certPrev').addEventListener('click',()=>goTo(current-1));

  window.addEventListener('resize',()=>{buildDots();goTo(0)});
  calcVisible(); buildDots(); goTo(0);
})();

/* ---- FORM SUBMIT FEEDBACK ---- */
document.getElementById('formSubmit').addEventListener('click',function(){
  this.innerHTML='   Sent! I\'ll reply soon.';
  this.style.background='linear-gradient(135deg,#06ffa5,#00b894)';
  setTimeout(()=>{
    this.innerHTML='   Send Message';
    this.style.background='';
  },3000);
});

/* ---- NAV SCROLL EFFECT ---- */
window.addEventListener('scroll',()=>{
  const nav = document.getElementById('nav');
  if(window.scrollY>50){
    nav.style.height='60px';
    nav.style.boxShadow='0 5px 30px rgba(0,0,0,0.3)';
  } else {
    nav.style.height='70px';
    nav.style.boxShadow='none';
  }
});

/* ---- ACTIVE NAV LINK ON SCROLL ---- */
const sections = document.querySelectorAll('section[id]');
const navLinks = document.querySelectorAll('.nav-links a');
const spy = new IntersectionObserver((entries)=>{
  entries.forEach(e=>{
    if(e.isIntersecting){
      navLinks.forEach(l=>l.style.color='');
      const link = document.querySelector(`.nav-links a[href="#${e.target.id}"]`);
      if(link) link.style.color='var(--accent)';
    }
  });
},{threshold:0.4});
sections.forEach(s=>spy.observe(s));

/* ---- LOADING SCREEN ---- */
(function(){
  const loader   = document.getElementById('loader');
  const bar      = document.getElementById('loaderBar');
  const pct      = document.getElementById('loaderPct');
  const status   = document.getElementById('loaderStatus');

  const steps = [
  { p: 5,  msg: 'Initializing neon core...' },
  { p: 10, msg: 'Loading futuristic fonts...' },
  { p: 15, msg: 'Activating UI modules...' },
  { p: 20, msg: 'Parsing data assets...' },
  { p: 25, msg: 'Connecting portfolio database...' },
  { p: 30, msg: 'Loading developer profile...' },
  { p: 35, msg: 'Generating smooth animations...' },
  { p: 40, msg: 'Compiling experience timeline...' },
  { p: 45, msg: 'Building skill charts...' },
  { p: 50, msg: 'Loading achievements...' },
  { p: 55, msg: 'Rendering projects...' },
  { p: 60, msg: 'Optimizing interface performance...' },
  { p: 65, msg: 'Applying neon lighting effects...' },
  { p: 70, msg: 'Creating cyberpunk environment...' },
  { p: 75, msg: 'Syncing interactive elements...' },
  { p: 80, msg: 'Enhancing visual experience...' },
  { p: 85, msg: 'Finalising interface...' },
  { p: 88, msg: 'Preparing dashboard...' },
  { p: 90, msg: 'Launching portfolio engine...' },
  { p: 92, msg: 'System check complete...' },
  { p: 94, msg: 'Almost ready...' },
    { p:95, msg:'10' },
    { p:95, msg:'9' },
    { p:95, msg:'8'},
    { p:95, msg:'7'},
    { p:95, msg:'6'},
    { p:95, msg:'5'},
    { p:95, msg:'4'},
    { p:95, msg:'3'},
    { p:95, msg:'2'},
    { p:95, msg:'1'},
    { p:97, msg: 'Access granted...' },
    { p:98, msg: 'Welcome Developer...' },
    { p:99, msg: 'Entering digital workspace...' },
    { p:100, msg:'Welcome to my portfolio website🚀' },
  ];

  let i = 0;
  function runStep(){
    if(i >= steps.length){ dismiss(); return; }
    const s = steps[i++];
    bar.style.width = s.p + '%';
    pct.textContent  = s.p + '%';
    status.textContent = s.msg;
    const delay = i === steps.length ? 600 : 280 + Math.random()*220;
    setTimeout(runStep, delay);
  }

  function dismiss(){
    setTimeout(()=>{
      loader.classList.add('hidden');
      setTimeout(()=>{ loader.style.display='none'; }, 750);
    }, 500);
  }

  // Start after a tiny delay so fonts are requested
  setTimeout(runStep, 200);
})();
